SELECT , p.id as pid, p.name as pname, d.id as did, d.name as dname
FROM resume r
LEFT JOIN position p ON r.positionId = p.id
LEFT JOIN department d ON r.departmentId = d.id


    AND r.name LIKE CONCAT('%',#{resume.name},'%')


    AND r.phone LIKE CONCAT('%',#{resume.phone},'%')


    AND r.education = #{resume.education}


    AND r.status = #{resume.status}


    AND r.positionId = #{resume.positionId}


    AND r.departmentId = #{resume.departmentId}


    AND r.workYears >= #{resume.workYears}


ORDER BY r.createTime DESC

  LIMIT #{page}, #{size}

SELECT COUNT(*) FROM resume r


    AND r.name LIKE CONCAT('%',#{resume.name},'%')


    AND r.phone LIKE CONCAT('%',#{resume.phone},'%')


    AND r.education = #{resume.education}


    AND r.status = #{resume.status}


    AND r.positionId = #{resume.positionId}


    AND r.departmentId = #{resume.departmentId}


    AND r.workYears >= #{resume.workYears}

SELECT r.*, p.name as pname, d.name as dname
FROM resume r
LEFT JOIN position p ON r.positionId = p.id
LEFT JOIN department d ON r.departmentId = d.id


    AND r.name LIKE CONCAT('%',#{resume.name},'%')


    AND r.phone LIKE CONCAT('%',#{resume.phone},'%')


    AND r.education = #{resume.education}


    AND r.status = #{resume.status}


    AND r.positionId = #{resume.positionId}


ORDER BY r.createTime DESC

