UPDATE resume
name = #{name}, gender = #{gender}, age = #{age}, education = #{education}, workYears = #{workYears}, phone = #{phone}, email = #{email}, expectedSalary = #{expectedSalary}, positionId = #{positionId}, departmentId = #{departmentId}, workExperience = #{workExperience}, educationExperience = #{educationExperience}, skills = #{skills}, selfEvaluation = #{selfEvaluation}, attachmentPath = #{attachmentPath}, status = #{status}, hrId = #{hrId}, remark = #{remark}, updateTime = NOW()
WHERE id = #{id,jdbcType=INTEGER}
